import React from "react";
import {AppBar, Toolbar, Button, Paper} from "@material-ui/core";

const NavBar = () =>{
    return(
        <AppBar position="absolute" variant="outlined" >
            <Toolbar>
                <Paper>
                    <Button color = "primary">
                        Resume
                    </Button>
                </Paper>
            </Toolbar>
        </AppBar>
    )
}
export default NavBar;
